import{_ as a,o as t,c as s,ag as n}from"./chunks/framework.DXGyWiRo.js";const u=JSON.parse('{"title":"Language Additions","description":"","frontmatter":{},"headers":[],"relativePath":"lang.md","filePath":"lang.md"}'),l={name:"lang.md"};function i(o,e,r,p,c,d){return t(),s("div",null,[...e[0]||(e[0]=[n(`<h1 id="language-additions" tabindex="-1">Language Additions <a class="header-anchor" href="#language-additions" aria-label="Permalink to &quot;Language Additions&quot;">​</a></h1><p>LinkedQL extends SQL to express structure and relationships directly in the query.</p><p>Instead of flattening data and reconstructing it in application code, you define the final structure directly in the query.</p><h2 id="meet-json-literals-inline-structuring" tabindex="-1">Meet JSON Literals (Inline Structuring) <a class="header-anchor" href="#meet-json-literals-inline-structuring" aria-label="Permalink to &quot;Meet JSON Literals (Inline Structuring)&quot;">​</a></h2><div class="language-js"><button title="Copy Code" class="copy"></button><span class="lang">js</span><pre class="shiki material-theme-palenight vp-code" tabindex="0"><code><span class="line"><span style="color:#C792EA;">const</span><span style="color:#BABED8;"> result </span><span style="color:#89DDFF;">=</span><span style="color:#89DDFF;font-style:italic;"> await</span><span style="color:#BABED8;"> db</span><span style="color:#89DDFF;">.</span><span style="color:#82AAFF;">query</span><span style="color:#BABED8;">(</span><span style="color:#89DDFF;">\`</span></span>
<span class="line"><span style="color:#C3E88D;">  SELECT</span></span>
<span class="line"><span style="color:#C3E88D;">    id,</span></span>
<span class="line"><span style="color:#C3E88D;">    { first: first_name, last: last_name } AS name,</span></span>
<span class="line"><span style="color:#C3E88D;">    { email, phone: phone_number } AS contact</span></span>
<span class="line"><span style="color:#C3E88D;">  FROM users</span></span>
<span class="line"><span style="color:#89DDFF;">\`</span><span style="color:#BABED8;">)</span><span style="color:#89DDFF;">;</span></span></code></pre></div><p>No mapping layer. No post-processing.</p><ul><li>the query returns exactly the shape your UI needs</li><li>no <code>map()</code> / <code>reduce()</code> / DTO transformation step</li><li>fewer mismatches between backend and frontend models</li></ul><hr><h2 id="meet-deeprefs-inline-relationships" tabindex="-1">Meet DeepRefs (Inline Relationships) <a class="header-anchor" href="#meet-deeprefs-inline-relationships" aria-label="Permalink to &quot;Meet DeepRefs (Inline Relationships)&quot;">​</a></h2><div class="language-js"><button title="Copy Code" class="copy"></button><span class="lang">js</span><pre class="shiki material-theme-palenight vp-code" tabindex="0"><code><span class="line"><span style="color:#C792EA;">const</span><span style="color:#BABED8;"> posts </span><span style="color:#89DDFF;">=</span><span style="color:#89DDFF;font-style:italic;"> await</span><span style="color:#BABED8;"> db</span><span style="color:#89DDFF;">.</span><span style="color:#82AAFF;">query</span><span style="color:#BABED8;">(</span><span style="color:#89DDFF;">\`</span></span>
<span class="line"><span style="color:#C3E88D;">  SELECT</span></span>
<span class="line"><span style="color:#C3E88D;">    title,</span></span>
<span class="line"><span style="color:#C3E88D;">    author ~&gt; {</span></span>
<span class="line"><span style="color:#C3E88D;">      id,</span></span>
<span class="line"><span style="color:#C3E88D;">      name,</span></span>
<span class="line"><span style="color:#C3E88D;">      profile ~&gt; { avatar_url }</span></span>
<span class="line"><span style="color:#C3E88D;">    } AS author</span></span>
<span class="line"><span style="color:#C3E88D;">  FROM posts</span></span>
<span class="line"><span style="color:#C3E88D;">  WHERE published = true</span></span>
<span class="line"><span style="color:#89DDFF;">\`</span><span style="color:#BABED8;">)</span><span style="color:#89DDFF;">;</span></span></code></pre></div><p>No need for an ORM or manual JOIN logic.</p><p>If you&#39;ve defined foreign key relationships in your tables, you can traverse them directly.</p><p>The above expresses the data the way the application already understands it:</p><ul><li>a post has an author</li><li>an author has a profile</li></ul><hr><h2 id="the-broader-idea" tabindex="-1">The Broader Idea <a class="header-anchor" href="#the-broader-idea" aria-label="Permalink to &quot;The Broader Idea&quot;">​</a></h2><p>Database logic is rarely just about returning rows. It is often more about aligning SQL semantics with application-level behavior and intents:</p><ul><li>navigating relationships</li><li>shaping results into application-ready structures</li><li>coordinating read and write intent</li></ul><p>This logic often spills out of SQL into ORMs, post-processing layers, and defensive glue code.</p><p>LinkedQL pulls that logic back into the query itself through a small set of SQL syntax extensions.</p><hr><h2 id="documentation" tabindex="-1">Documentation <a class="header-anchor" href="#documentation" aria-label="Permalink to &quot;Documentation&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">Capability</th><th style="text-align:left;">What It Adds</th><th style="text-align:left;">Docs</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>DeepRefs</strong></td><td style="text-align:left;">Direct relationship traversal in SQL</td><td style="text-align:left;"><a href="/lang/deeprefs">DeepRefs</a></td></tr><tr><td style="text-align:left;"><strong>JSON Literals</strong></td><td style="text-align:left;">Direct structuring in SQL</td><td style="text-align:left;"><a href="/lang/json-literals">JSON Literals</a></td></tr><tr><td style="text-align:left;"><strong>UPSERT</strong></td><td style="text-align:left;">A direct UPSERT statement in SQL</td><td style="text-align:left;"><a href="/lang/upsert">UPSERT</a></td></tr><tr><td style="text-align:left;"><strong>Version Binding</strong></td><td style="text-align:left;">Query-level version-binding syntax</td><td style="text-align:left;"><a href="/lang/version-binding">Version Binding</a></td></tr></tbody></table>`,23)])])}const y=a(l,[["render",i]]);export{u as __pageData,y as default};
